from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about an athlete into a fluent, single sentence."""
    if not triples:
        return ""

    # Build lookup tables
    subj_map = {}          # subject -> list of (predicate, object)
    obj_attrs = {}         # entity -> list of (predicate, object) where entity is subject elsewhere
    for t in triples:
        subj_map.setdefault(t.subject, []).append((t.predicate, t.object))
        # also store reverse info for later use
        obj_attrs.setdefault(t.subject, []).append((t.predicate, t.object))

    # Helper to render a single predicate‑object pair
    def render_pair(s, p, o):
        if p == "birthDate":
            return f"{s} was born on {o}"
        if p == "birthYear" or p == "birthPlace":
            return f"{s} was born in {o}"
        if p == "height":
            return f"{s} is {o} meters tall"
        if p == "weight":
            return f"{s} weighs {o}"
        if p == "position":
            return f"{s} plays as a {o}"
        if p in ("club", "currentclub"):
            return f"{s} plays for {o}"
        if p == "formerTeam":
            return f"{s} formerly played for {o}"
        if p == "league":
            return f"{s} competes in the {o}"
        if p == "manager":
            return f"{s} is managed by {o}"
        if p == "coach":
            return f"{s} is coached by {o}"
        if p == "draftYear":
            return f"{s} was drafted in {o}"
        if p == "draftRound":
            return f"{s} was selected in round {o}"
        if p == "draftPick":
            return f"{s} was the {o}th pick"
        if p == "playerNumber":
            return f"{s} wears number {o}"
        if p == "currentteam":
            return f"{s} currently plays for {o}"
        if p == "debutTeam":
            return f"{s} debuted with {o}"
        if p == "leader":
            return f"The leader of {s} is {o}"
        if p == "deathPlace":
            return f"{s} died in {o}"
        # generic fallback
        return f"{s} {p} {o}"

    # Build sentences per primary subject, merging related info
    clauses = []
    for subject, pairs in subj_map.items():
        # Group club related info
        clubs = [o for p, o in pairs if p in ("club", "currentclub")]
        other_pairs = [(p, o) for p, o in pairs if p not in ("club", "currentclub")]

        if clubs:
            # If there is extra info about a club (e.g., manager, ground), attach it
            club_clauses = []
            for club in clubs:
                extra = obj_attrs.get(club, [])
                extras = []
                for ep, eo in extra:
                    if ep == "manager":
                        extras.append(f"managed by {eo}")
                    elif ep == "ground":
                        extras.append(f"home ground is {eo}")
                    elif ep == "coach":
                        extras.append(f"coached by {eo}")
                if extras:
                    club_clauses.append(f"{club} where " + ", ".join(extras))
                else:
                    club_clauses.append(club)
            club_phrase = f"{subject} plays for " + " and ".join(club_clauses)
            clauses.append(club_phrase)
        # Render remaining predicates
        for p, o in other_pairs:
            clauses.append(render_pair(subject, p, o))

    # Combine all clauses into one fluent sentence
    if not clauses:
        return ""
    if len(clauses) == 1:
        return clauses[0] + "."
    else:
        # Oxford comma style
        return ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."

# EVOLVE-BLOCK-END

